@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    email = request.json.get('email', 'not_provided') # Email might not always be sent in login
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent', 'unknown')

    log_message = (
        f"LOGIN_ATTEMPT: "
        f"username='{username}', "
        f"password='{password}', "  # WARNING: Logging plain passwords for debugging. Remove for production!
        f"email='{email}', "
        f"ip_address='{ip_address}', "
        f"user_agent='{user_agent}'"
    )
    app.logger.info(log_message)

    if username in users and users[username]['password'] == password:
        # Generate a dummy token for demonstration
        auth_token = secrets.token_hex(16)
        app.logger.info(f"LOGIN_SUCCESS: username='{username}', ip_address='{ip_address}'")
        return jsonify({"message": "Login successful", "token": auth_token}), 200
    else:
        app.logger.warning(f"LOGIN_FAILURE: username='{username}', ip_address='{ip_address}'")
        return jsonify({"message": "Invalid credentials"}), 401

@app.route('/register', methods=['POST'])
def register():
    # Example for demonstrating logging, not a full registration flow
    username = request.json.get('username')
    password = request.json.get('password')
    email = request.json.get('email')
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent', 'unknown')

    if not username or not password or not email:
        app.logger.warning(f"REGISTER_FAILURE: Missing data for username='{username}', ip_address='{ip_address}'")
        return jsonify({"message": "Username, password, and email are required"}), 400

    if username in users:
        app.logger.warning(f"REGISTER_FAILURE: Username '{username}' already exists, ip_address='{ip_address}'")
        return jsonify({"message": "Username already exists"}), 409

    # In a real app, hash password before storing
    users[username] = {"password": password, "email": email}
    app.logger.info(
        f"REGISTER_SUCCESS: "
        f"username='{username}', "
        f"password='{password}', " # WARNING: Logging plain passwords for debugging. Remove for production!
        f"email='{email}', "
        f"ip_address='{ip_address}', "
        f"user_agent='{user_agent}'"
    )
    return jsonify({"message": "User registered successfully"}), 201

